import base64

import streamlit as st
from speak_js import make_speak_fn


def _sync_summary_play_state(
    summary: str, audio_file_name: str, has_cached_audio: bool
) -> None:
    """새 요약이나 새 오디오가 들어오면 자동 재생 토큰을 갱신한다."""
    current_key = f'{summary}\n{audio_file_name}\n{int(has_cached_audio)}'
    if st.session_state.get('summary_play_key') == current_key:
        return
    st.session_state.summary_play_key = current_key
    st.session_state.summary_play_token = (
        int(st.session_state.get('summary_play_token', 0)) + 1
    )


def render_summary_panel():
    summary = st.session_state.get('summary', '')
    keywords = st.session_state.get('memo_keywords', [])
    audio = st.session_state.get('audio_bytes')
    audio_mime = st.session_state.get('audio_mime') or 'audio/wav'
    audio_file_name = st.session_state.get('audio_file_name') or 'readmate.wav'
    has_cached_audio = bool(audio)
    has_quiz = bool(st.session_state.get('quiz', []))
    if not summary:
        return

    _sync_summary_play_state(summary, audio_file_name, has_cached_audio)

    # ── 요약 카드 (타이틀 + 본문 묶음) ──────────────
    st.markdown(
        f"""
    <div class="rm-summary-card">
      <div class="rm-card-title"><img src="data:image/png;base64," style="width:1.4rem;height:1.4rem;object-fit:contain;vertical-align:middle;" alt="요약 아이콘"> 요약</div>
      <div class="rm-body">{summary}</div>
    </div>
    """,
        unsafe_allow_html=True,
    )

    if keywords:
        # ── 방어 처리: 문자열이면 콤마/개행 분리 ──────────
        if isinstance(keywords, str):
            keywords = [
                k.strip() for k in keywords.replace('\n', ',').split(',') if k.strip()
            ]

        if keywords:
            items_html = ''.join(f'<li class="kp-item">{k}</li>' for k in keywords)
            st.markdown(
                f"""
<br>
<div class="kp-box">
  <div class="kp-title">Key Points</div>
  <ul class="kp-list">{items_html}</ul>
</div>
<style>
.kp-box {{
  background: #faf4ef;
  border: 1.5px solid #c4a898;
  border-left: 4px solid #b07060;
  border-radius: 14px;
  padding: 1rem 1.2rem 1rem 1.4rem;
  margin-top: .4rem;
  margin-bottom: 1.2rem;
}}
.kp-title {{
  font-size: 1rem;
  font-weight: 900;
  color: #b07060;
  margin-bottom: .55rem;
  letter-spacing: .03em;
}}
.kp-list {{
  margin: 0;
  padding-left: 1.3rem;
  list-style: disc;
}}
.kp-item {{
  font-size: .97rem;
  font-weight: 600;
  color: #1a0f0a;
  line-height: 1.85;
  word-break: keep-all;
}}
</style>
""",
                unsafe_allow_html=True,
            )

    with st.expander('📄 원문 보기', expanded=False):
        st.markdown(
            f'<div class="rm-body" style="font-size:.83rem;">'
            f'{st.session_state.get("raw_text", "")}</div>',
            unsafe_allow_html=True,
        )

    # ── 키보드 힌트 ───────────────────────────────
    st.markdown(
        """
    <div class="kb-hint">
      <strong>Q</strong> : 질의응답 &nbsp;|&nbsp;
      <strong>P</strong> : 퀴즈 &nbsp;|&nbsp;
      <strong>R</strong> : 다시 듣기 &nbsp;|&nbsp;
      <strong>Backspace</strong> : 기능 선택으로
    </div>
    """,
        unsafe_allow_html=True,
    )

    # ── 버튼 ─────────────────────────────────────
    c1, c2, c3 = st.columns(3)
    with c1:
        if st.button('다시 듣기', use_container_width=True, key='sum_r'):
            st.session_state.summary_play_token = (
                int(st.session_state.get('summary_play_token', 0)) + 1
            )
            st.rerun()
    with c2:
        if st.button('질의응답', use_container_width=True, key='sum_q'):
            st.session_state.active_panel = 'qa'
            st.rerun()
    with c3:
        if st.button('퀴즈', use_container_width=True, key='sum_p'):
            st.session_state.active_panel = 'quiz'
            st.rerun()

    # ── 자동 낭독 + 전역 키 ───────────────────────
    kw = ', '.join(keywords) if keywords else ''
    s = summary.replace('\\', '\\\\').replace("'", "\\'").replace('\n', ' ')
    k = kw.replace("'", "\\'")
    keyboard_help = (
        'Q를 누르면 질의응답, P를 누르면 퀴즈, R을 누르면 다시 듣기입니다.'
        if has_quiz
        else 'Q를 누르면 질의응답, R을 누르면 다시 듣기입니다.'
    )
    quiz_key_action = (
        "speak('퀴즈로 이동합니다.', ()=>goTo('quiz'));"
        if has_quiz
        else "speak('현재 퀴즈가 준비되지 않았습니다.');"
    )
    play_token = int(st.session_state.get('summary_play_token', 0))
    audio_src = (
        f'data:{audio_mime};base64,{base64.b64encode(audio).decode()}'
        if has_cached_audio
        else ''
    )

    st.iframe(
        f"""
<script>
(function() {{
  {make_speak_fn()}

  window.lastQueueToken = 0;
  const playToken = {play_token};
  const hasCachedAudio = {'true' if has_cached_audio else 'false'};
  const cachedAudioSrc = {repr(audio_src)};

  function claimAudio(audio) {{
    try {{
      if (window.parent.speechSynthesis) window.parent.speechSynthesis.cancel();
    }} catch (err) {{}}
    try {{
      const owner = window.parent;
      const prev = owner.__rmCurrentAudio;
      if (prev && prev !== audio) {{
        prev.pause();
        prev.currentTime = 0;
      }}
      owner.__rmCurrentAudio = audio;
    }} catch (err) {{}}
  }}

  function playCachedSummary() {{
    if (!cachedAudioSrc) return;
    const audio = new Audio(cachedAudioSrc);
    audio.onended = () => {{
      try {{
        if (window.parent.__rmCurrentAudio === audio) window.parent.__rmCurrentAudio = null;
      }} catch (err) {{}}
    }};
    audio.onerror = () => {{
      try {{
        if (window.parent.__rmCurrentAudio === audio) window.parent.__rmCurrentAudio = null;
      }} catch (err) {{}}
    }};
    claimAudio(audio);
    audio.currentTime = 0;
    audio.play().catch(() => {{}});
  }}

  function speakQueue(arr, i, token, cb) {{
    if (token !== window.lastQueueToken) return; // 큐가 취소됨
    if (i >= arr.length) {{ if (cb) cb(); return; }}
    speak(arr[i], () => {{
      if (token === window.lastQueueToken) speakQueue(arr, i + 1, token, cb);
    }});
  }}

  function readSummary() {{
    const token = Date.now();
    window.lastQueueToken = token;

    const texts = [
      '{s}',
      {'`핵심 문장: ' + k + '`' if kw else "''"},
      `{keyboard_help}`
    ].filter(t => t && t.trim() && t !== "''");

    speakQueue(texts, 0, token, null);
  }}

  function syncSummaryPlayback() {{
    const owner = window.parent;
    if (owner.__rmSummaryPlayToken === playToken) return;
    owner.__rmSummaryPlayToken = playToken;
    if (hasCachedAudio) playCachedSummary();
    else readSummary();
  }}

  function goTo(panel) {{
    window.lastQueueToken = 0; // 페이지 이동 시 큐 중단
    if (window.currentAudio) {{ window.currentAudio.pause(); window.currentAudio = null; }}
    if (window.speechSynthesis) window.speechSynthesis.cancel();

    const btns = window.parent.document.querySelectorAll('button');
    for (const b of btns) {{
      if (panel==='qa'   && b.innerText.includes('질의응답')) {{ b.click(); return; }}
      if (panel==='quiz' && b.innerText.includes('퀴즈')) {{ b.click(); return; }}
      if (panel==='back' && b.innerText.trim()==='ReadMate') {{ b.click(); return; }}
    }}
  }}

  function onKey(e) {{
    const tag = e.target.tagName;
    if (tag==='INPUT'||tag==='TEXTAREA') return;
    if (e.key.toLowerCase()==='q') {{ speak('질의응답으로 이동합니다.', ()=>goTo('qa')); }}
    if (e.key.toLowerCase()==='p') {{ {quiz_key_action} }}
    if (e.key.toLowerCase()==='r') {{ hasCachedAudio ? playCachedSummary() : readSummary(); }}
    if (e.key==='Backspace') {{ e.preventDefault(); speak('기능 선택으로 돌아갑니다.', ()=>goTo('back')); }}
  }}

  if (!window.summaryInitialized) {{
    document.addEventListener('keydown', onKey);
    try {{ window.parent.document.addEventListener('keydown', onKey); }} catch(err) {{}}
    window.summaryInitialized = true;
  }}
  syncSummaryPlayback();
}})();
</script>
""",
        height=1,
    )
